    88→template <typename KEY_TYPE, typename POOL_TYPE> void ConnPoolMap<KEY_TYPE, POOL_TYPE>::clear() {
    89→  Common::AutoDebugRecursionChecker assert_not_in(recursion_checker_);
    90→  for (auto& pool_pair : active_pools_) {
