   106→template <typename KEY_TYPE, typename POOL_TYPE>
   107→void ConnPoolMap<KEY_TYPE, POOL_TYPE>::drainConnections(
   108→    Envoy::ConnectionPool::DrainBehavior drain_behavior) {
   109→  // Copy the `active_pools_` so that it is safe for the call to result
   110→  // in deletion, and avoid iteration through a mutating container.
   111→  std::vector<POOL_TYPE*> pools;
   112→  pools.reserve(active_pools_.size());
   113→  for (auto& pool_pair : active_pools_) {
   114→    pools.push_back(pool_pair.second.get());
   115→  }
   116→
   117→  for (auto* pool : pools) {
   118→    pool->drainConnections(drain_behavior);
   119→  }
   120→}
