   122→template <typename KEY_TYPE, typename POOL_TYPE>
   123→bool ConnPoolMap<KEY_TYPE, POOL_TYPE>::freeOnePool() {
   124→  // Try to find a pool that isn't doing anything.
   125→  auto pool_iter = active_pools_.begin();
   126→  while (pool_iter != active_pools_.end()) {
   127→    if (!pool_iter->second->hasActiveConnections()) {
   128→      break;
   129→    }
   130→    ++pool_iter;
   131→  }
   132→
   133→  if (pool_iter != active_pools_.end()) {
   134→    // We found one. Free it up, and let the caller know.
   135→    active_pools_.erase(pool_iter);
   136→    host_->cluster().resourceManager(priority_).connectionPools().dec();
   137→    return true;
   138→  }
   139→
   140→  return false;
   141→}
